-- Enrichment marathon batch: MeetEdgar, Meez, Megaphone, Meilisearch, Melio, Meltano, Meltwater, Mem

-- ── MeetEdgar ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MeetEdgar is a social media scheduling tool that automatically recycles evergreen posts from a content library to keep social profiles active with minimal manual work.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$24.91/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Edina, Minnesota, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MeetEdgar Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MeetEdgar review covering pricing, content recycling automation, category queues, integrations, pros and cons, and how it compares to other social schedulers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MeetEdgar is a social media management and content-recycling platform founded in 2014 by entrepreneur Laura Roeder, along with her husband Chris Williams. The company grew out of Roeder's earlier social-media training business, LKR Social Media, after she validated demand for an automated scheduling tool through her Social Brilliant course. MeetEdgar was bootstrapped and self-funded from the profits of that earlier business rather than raising venture capital, and it grew into a multi-million-dollar, fully remote, bootstrapped company under Roeder's leadership. In January 2022, MeetEdgar was acquired by SureSwift Capital, a company that buys and operates profitable SaaS businesses, in a reported seven-figure deal. The product, nicknamed 'Edgar,' is built around a core idea that differentiates it from most competitors: rather than a simple calendar-based scheduler, MeetEdgar organizes social posts into content categories (such as blog posts, quotes, or promotions) and automatically re-queues and reshares evergreen posts from a content library on an ongoing rotating schedule, so users do not have to keep creating or re-scheduling the same type of update. It supports major networks including Facebook, Instagram, LinkedIn, Pinterest, and X (formerly Twitter), along with a browser extension for quick content capture, a link-in-bio feature, RSS-to-social automation, A/B testing of post variations, and analytics on category performance. MeetEdgar targets small businesses, solo entrepreneurs, marketing agencies, and content creators who publish evergreen content and want to reduce the time spent on manual social posting. Pricing is structured around two core plans: the entry-level 'Eddie' plan, aimed at freelancers and solo entrepreneurs, and the higher-tier 'Edgar' plan, aimed at growing businesses and agencies needing more accounts and automations; both plans support the same 20 team member allowance but differ in the number of connected social accounts, weekly automations, and content categories. Annual billing offers a discount over the month-to-month rate, and additional social accounts can be added a la carte. A free trial is available. MeetEdgar's main competitors include Buffer, Hootsuite, Later, SocialBee, and Sprout Social; its key differentiation is the automated content-recycling model that keeps a library of evergreen posts perpetually circulating, which appeals particularly to solopreneurs and small teams that lack the bandwidth to schedule fresh content every day.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fa6c1b1f-237c-41bd-973b-da2acee05d7b';

