-- ── Meez ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Meez is recipe management and food-costing software that helps professional kitchens create, scale, cost, and standardize recipes in place of spreadsheets and paper.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$19/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Meez Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Meez review covering recipe management, food costing, menu engineering, pricing plans, pros and cons, and alternatives for restaurants and culinary teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Meez (getmeez.com) is recipe management and food-costing software built specifically for professional kitchens, restaurant groups, and culinary teams. It was founded by Josh Sharkey, a chef and restaurant operator with more than two decades in the industry who previously cooked in Michelin-starred kitchens and opened Bark Hot Dogs in Brooklyn. Sharkey built Meez after growing frustrated managing recipes across spreadsheets, PDFs, and disconnected back-office tools; the platform spent over two years in development before launching publicly in late 2020, and the company is headquartered in New York City. Meez functions as a centralized, interactive hub where culinary teams create, scale, cost, and collaborate on recipes with built-in unit conversions, automated yield calculations, and version control so every team member works from the same up-to-date recipe. Core capabilities include recipe costing that updates automatically as ingredient prices change, an AI-assisted copy-paste recipe importer that converts existing paper or digital recipes into structured Meez recipes, inventory management, invoice processing that feeds live cost data back into recipes, menu building and menu engineering tools, USDA nutrition-label and allergen tagging, and integrations with point-of-sale and back-office accounting systems such as Restaurant365. The product is aimed at independent chefs, single-location restaurants, multi-unit restaurant groups, hotels, and large contract foodservice and hospitality organizations that need consistent recipes, accurate food costs, and standardized training materials across many cooks and locations. Meez is priced on a tiered subscription model: a Starter plan for individual chefs organizing recipes and basic costing, a Pro plan for single-kitchen teams needing training and prep tools, a Premium plan for small multi-unit operators wanting real-time costing and BackOffice system connections, and a custom-quoted Enterprise plan for large hospitality groups needing POS integration, SLA-backed support, and team analytics. Annual billing offers roughly a 20 percent discount versus paying monthly, and add-ons such as additional recipe-viewer locations, extra automated cost feeds, and data-warehouse syncs are available for larger operations. Meez's main competitors include CrunchTime, Yourwaydigital, Apicbase, MarketMan, and general-purpose spreadsheet-based recipe costing; its key differentiator is that it was built by an actual chef specifically for the workflow of professional kitchens, emphasizing recipe consistency, food-cost visibility, and staff training rather than treating recipes as a secondary feature of broader restaurant-management software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6cf21005-e4bd-49c2-a890-817f14482aab';

