-- ── Meilisearch ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Meilisearch is an open-source, typo-tolerant search engine written in Rust that developers self-host or run as a managed cloud service to add fast search to apps.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted), Cloud plans from $23/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Meilisearch Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Meilisearch review covering open-source search, typo tolerance, vector and hybrid search, self-hosting versus Cloud pricing, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Meilisearch is an open-source search engine designed to deliver fast, relevant, typo-tolerant search results with minimal configuration. It was founded in 2018 in Paris, France, by three college friends, Quentin de Quelen (CEO), Clement Renault (CTO), and Thomas Payet (COO), who previously worked together at the European e-commerce company Veepee and at Louis Vuitton before starting Meilisearch. The engine is written in Rust for performance and memory safety, and the core product, Meilisearch Community Edition, is released under the MIT license, allowing anyone to self-host it with no usage restrictions. Meilisearch is designed to be an accessible alternative to heavier, more complex search infrastructure like Elasticsearch or Apache Solr, emphasizing a simple REST API, fast setup time, and reasonable relevance out of the box without extensive tuning. Core capabilities include typo tolerance, faceted search and filtering, sorting, geosearch, multi-language and multi-tenant search, and more recently hybrid and vector search combining traditional keyword search with semantic embeddings for AI-powered retrieval use cases such as retrieval-augmented generation. The company monetizes through Meilisearch Cloud, a fully managed hosted version of the engine, offered in two pricing structures: a usage-based plan starting around 30 dollars per month billed for search and document volume, and a resource-based plan starting around 23 dollars per month where customers pay for dedicated CPU, RAM, and storage, which is better suited to high-traffic or vector-search workloads. An Enterprise tier offers a custom quote with additional capabilities such as sharding, S3-based snapshots, premium SLAs, and dedicated support for large-scale or self-hosted enterprise deployments. Meilisearch targets software developers and engineering teams building search into websites, e-commerce storefronts, documentation sites, SaaS products, and AI applications, ranging from individual developers self-hosting the open-source engine for free to venture-backed startups and enterprises using Meilisearch Cloud. The company remains relatively small, with roughly two to three dozen employees distributed across Europe, North America, and South America, with a largely remote team centered around its Paris headquarters. Meilisearch's primary competitors include Algolia, Elasticsearch, Typesense, and OpenSearch; its key differentiation is combining an open-source, self-hostable core with the developer-experience simplicity typically associated with proprietary hosted search products like Algolia, at a lower price point.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7d00f455-f1c1-4f08-8b80-9aa4fcbc5ec0';

